<?php namespace App\Repositories\Health;use App\Repositories\BaseRepository;use App\Models\Health\VaccinationRecord;use Illuminate\Database\Eloquent\Collection;class VaccinationRecordRepository extends BaseRepository{    public function __construct(VaccinationRecord $model)    {        $this->model = $model;        parent::__construct($model);    }    public function findByStudent(int $studentId): Collection    {        return $this->findByField('student_id', $studentId);    }    public function findByVaccineName(string $vaccineName): Collection    {        return $this->findByField('vaccine_name', $vaccineName);    }    public function findByStatus(string $status): Collection    {        return $this->findByField('status', $status);    }    public function getUpcomingVaccinations(int $days = 30): Collection    {        return $this->query()->where('next_due_date', '>=', now())->where('next_due_date', '<=', now()->addDays($days))->orderBy('next_due_date', 'asc')->get();    }    public function getOverdueVaccinations(): Collection    {        return $this->query()->where('next_due_date', '<', now())->where('status', 'pending')->get();    }    public function getCompletedVaccinations(int $studentId): Collection    {        return $this->query()->where('student_id', $studentId)->where('status', 'completed')->get();    }    public function markAsCompleted(int $id, array $data = []): bool    {        $updateData = array_merge($data, [            'status' => 'completed',            'vaccination_date' => $data['vaccination_date'] ?? now(),        ]);        return $this->update($id, $updateData);    }    public function getByDateRange(string $startDate, string $endDate): Collection    {        return $this->query()->whereBetween('vaccination_date', [$startDate, $endDate])->get();    }}